import sqlite3

# Connect to the database
conn = sqlite3.connect('financial_transactions.db')
cursor = conn.cursor()

# Create a table to store financial transactions
cursor.execute('''CREATE TABLE IF NOT EXISTS transactions (
    transaction_id INTEGER PRIMARY KEY,
    account_number TEXT,
    amount REAL,
    transaction_type TEXT
)''')

# Function to process financial transactions and update account balances
def process_transactions(transactions):
    for transaction in transactions:
        account_number = transaction['account_number']
        amount = transaction['amount']
        transaction_type = transaction['transaction_type']

        # Update account balance based on transaction type
        if transaction_type == 'deposit':
            cursor.execute('''UPDATE accounts SET balance = balance + ? WHERE account_number = ?''', (amount, account_number))
        elif transaction_type == 'withdrawal':
            cursor.execute('''UPDATE accounts SET balance = balance - ? WHERE account_number = ?''', (amount, account_number))

    # Commit changes to the database
    conn.commit()

# Example usage
transactions = [
    {'account_number': '12345', 'amount': 500, 'transaction_type': 'deposit'},
    {'account_number': '67890', 'amount': 200, 'transaction_type': 'withdrawal'}
]

process_transactions(transactions)

# Close the database connection
conn.close()